#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n,k;
    cin>>n>>k;
    for(int i=1;i<=k;i++){
        n+=1;
        if(n%3==0)n/=3;
        if(n==2){
            if((k-i)%2)cout<<1;
            else cout<<2;
            return 0;
        }
    }
    cout<<n;
    return 0;
}
